mapper.select:
SELECT COUNT(comment_no)
FROM tbl_community_comment
WHERE post_no = #{postNo}

mapper.update:
UPDATE tbl_community_post
SET post_view_count = post_view_count + 1
WHERE post_no = #{postNo}

mapper.select:
SELECT tcp.post_no, tcp.user_no, tcp.post_title, tcp.user_nickname, tcp.post_date, tcp.post_content, tcp.post_view_count, ( SELECT COUNT(post_like_no) FROM tbl_post_like tpl WHERE tpl.post_no = tcp.post_no ) AS like_count, tpi.post_img_system_name, tpi.post_img_origin_name
FROM tbl_community_post tcp LEFT JOIN tbl_post_image tpi ON tpi.post_no = tcp.post_no
WHERE tcp.post_no = #{postNo}

SELECT tcc.comment_no, tcc.user_no, tcc.user_nickname, tcc.comment_content, tcc.post_date
FROM tbl_community_comment tcc
WHERE tcc.post_no = #{postNo}
ORDER BY tcc.post_date DESC, tcc.comment_no DESC
LIMIT #{startRow}, #{endRow}

mapper.insert:
INSERT INTO tbl_post_like
(
    post_no,
    user_no
)
VALUES
(
    #{postNo},
    #{userNo}
)
